  window.EXTRA_READ_STORIES.push(...[{"id":"es-manana","title":"Mañana en la ciudad","subtitle":"Morning in the city","trail":"green-circle","categoryId":"es","sentences":[{"foreign":"¡Buenos días!","en":"Good morning!"},{"foreign":"Hola. Acabo de llegar.","en":"Hi. I just arrived."},{"foreign":"Hace frío, pero brilla el sol.","en":"It's cold, but the sun is shining."},{"foreign":"Cojo la bici pública por la calle peatonal.","en":"I'm taking the city bike along the pedestrian street."},{"foreign":"Perdone, ¿dónde está la parada del tranvía?","en":"Excuse me, where is the tram stop?"},{"foreign":"Todo recto, por la acera, en el cruce.","en":"Straight ahead, on the sidewalk, at the intersection."},{"foreign":"Gracias. ¿Hay una línea al centro ahora?","en":"Thanks. Is there a line into the center now?"},{"foreign":"Sí. Mira el horario, o coge un taxi si tienes prisa.","en":"Yes. Check the timetable, or take a taxi if you're in a hurry."},{"foreign":"Muchas gracias. ¡Que tenga un buen día!","en":"Thank you so much. Have a nice day!"},{"foreign":"No hay de qué. ¡Suerte!","en":"No problem. Good luck!"}],"glosses":{"Acabo de":"I just","llegar":"arrive","brilla":"is shining","bici pública":"city bike","calle peatonal":"pedestrian street","parada":"stop","tranvía":"tram","Todo recto":"straight ahead","acera":"sidewalk","cruce":"intersection","línea":"line","centro":"center","horario":"timetable","taxi":"taxi","prisa":"hurry","Suerte":"good luck"}},{"id":"es-cafe","title":"Un café, por favor","subtitle":"Ordering coffee","trail":"green-circle","categoryId":"es","sentences":[{"foreign":"¡Hola! ¿Hay sitio libre aquí en el café?","en":"Hi! Is there a free table here in the café?"},{"foreign":"Sí. ¿Quiere ver la carta?","en":"Yes. Would you like to look at the menu?"},{"foreign":"Un café, por favor. Sin leche.","en":"One coffee, please. Without milk."},{"foreign":"¿Quiere pedir desayuno también? Tenemos té, zumo y bocadillo de queso.","en":"Would you also like to order breakfast? We have tea, juice, and cheese sandwiches."},{"foreign":"¿Qué me recomienda?","en":"What do you recommend?"},{"foreign":"La sopa vegetariana está buena hoy. Postre más tarde si quiere.","en":"The vegetarian soup is good today. Dessert later if you want."},{"foreign":"Un bocadillo de queso, por favor. ¿Está picante?","en":"A cheese sandwich, please. Is it spicy?"},{"foreign":"No, suave. Abrimos hasta las tres. Para llevar está bien si tiene prisa.","en":"No, mild. We're open until three. Takeaway is fine if you're in a hurry."},{"foreign":"¿Me trae la cuenta ahora? ¿La propina es habitual aquí?","en":"Can I get the bill now? Is tipping usual here?"},{"foreign":"Sí. Son cuarenta y cinco euros. ¡Que tenga un buen día!","en":"Yes. That's forty-five euros. Have a nice day!"}],"glosses":{"sitio libre":"free table","café":"café","carta":"menu","Sin leche":"without milk","desayuno":"breakfast","té":"tea","zumo":"juice","recomienda":"recommend","vegetariana":"vegetarian","bocadillo de queso":"cheese sandwich","Postre":"dessert","picante":"spicy","suave":"mild","Para llevar":"takeaway","cuenta":"bill","propina":"tip","cuarenta y cinco":"forty-five"}},{"id":"es-tren","title":"En el tren","subtitle":"On the train","trail":"green-circle","categoryId":"es","sentences":[{"foreign":"¿Este tren va a Madrid?","en":"Does this train go to Madrid?"},{"foreign":"Sí, exacto. Andén cuatro. La siguiente salida es en diez minutos.","en":"Yes, that's right. Platform four. Next departure in ten minutes."},{"foreign":"¿Dónde compro el billete? ¿Sirve el abono mensual?","en":"Where do I buy a ticket? Can I use a monthly pass?"},{"foreign":"En la app o en la máquina. Si no, un billete sencillo vale.","en":"In the app or at the machine. Otherwise a one-way ticket is fine."},{"foreign":"Billete sencillo, por favor. Ventanilla, si puede. ¿Qué zona es?","en":"One-way ticket, please. A window seat, if possible. Which zone is it?"},{"foreign":"Zona uno a tres. Hay un poco de retraso en hora punta.","en":"Zones one to three. There's a bit of a delay in rush hour."},{"foreign":"¿Cuánto tarda entonces? Tengo que coger un transbordo.","en":"How long does it take then? I need to make a transfer."},{"foreign":"Unas dos horas. La estación final es Madrid Atocha.","en":"About two hours. The last stop is Madrid Atocha."},{"foreign":"Bien. ¿Hay aparcamiento en la estación si vengo en coche la próxima vez?","en":"Good. Is there parking at the station if I come by car next time?"},{"foreign":"Sí, pero cuesta. ¡Buen viaje!","en":"Yes, but it costs. Have a nice trip!"}],"glosses":{"exacto":"that's right","Andén":"platform","salida":"departure","billete":"ticket","abono mensual":"monthly pass","máquina":"ticket machine","sencillo":"one-way","zona":"zone","retraso":"delay","hora punta":"rush hour","transbordo":"transfer","Unas":"about","estación final":"terminus","aparcamiento":"parking"}},{"id":"es-biblioteca","title":"En la biblioteca","subtitle":"At the library","trail":"blue-square","categoryId":"es","sentences":[{"foreign":"Hola, busco un sitio tranquilo para estudiar.","en":"Hi, I'm looking for a quiet place to study."},{"foreign":"Arriba hay mesas libres junto a la ventana. El aula está ocupada, y el laboratorio también.","en":"Upstairs there are free tables by the window. The classroom is busy, and the lab too."},{"foreign":"¿Hasta qué hora abren?","en":"How late are you open?"},{"foreign":"Hasta las nueve de la noche. El auditorio cierra antes.","en":"Until nine in the evening. The lecture hall closes earlier."},{"foreign":"¿Puedo sacar libros con el carné de estudiante? Vivo en una residencia cerca.","en":"Can I borrow books with a student ID? I live in student housing nearby."},{"foreign":"Sí. ¿Necesita algo de la lista de lectura del curso?","en":"Yes. Do you need anything from the reading list for your course?"},{"foreign":"Quizá más tarde. Primero tengo trabajo en grupo con un compañero. ¿Puede repetir eso?","en":"Maybe later. First I have group work with a classmate. Could you repeat that?"},{"foreign":"Recuerde tomar apuntes. La tutoría del profesor es mañana. La inscripción al laboratorio es online.","en":"Remember to take notes. The teacher's office hours are tomorrow. Lab enrollment is online."},{"foreign":"Gracias. Espero aprobar el examen. El trabajo de fin de grado viene después.","en":"Thanks. I hope I'll pass the exam. The thesis comes later."},{"foreign":"¡Suerte con el examen la semana que viene!","en":"Good luck with the exam next week!"}],"glosses":{"tranquilo":"quiet","estudiar":"to study","libres":"free","ocupada":"busy","laboratorio":"lab","auditorio":"lecture hall","carné de estudiante":"student ID","residencia":"student housing","lista de lectura":"reading list","curso":"course","trabajo en grupo":"group work","compañero":"classmate","repetir":"to repeat","apuntes":"notes","tutoría":"office hours","profesor":"teacher","inscripción":"enrollment","aprobar":"to pass","examen":"exam","fin de grado":"thesis"}},{"id":"es-mercado","title":"En el mercado","subtitle":"At the market","trail":"blue-square","categoryId":"es","sentences":[{"foreign":"Hola. ¿Hay oferta en el supermercado hoy?","en":"Hi. Is there a deal at the supermarket today?"},{"foreign":"Sí, las verduras están baratas. El pollo también está de oferta.","en":"Yes, vegetables are cheap. Chicken is on sale too."},{"foreign":"¿Cuánto cuesta ese queso?","en":"How much is that cheese?"},{"foreign":"Treinta euros la unidad. ¿Quiere una bolsa?","en":"Thirty euros each. Would you like a bag?"},{"foreign":"Sí, por favor. Me llevo dos quesos y cuatro manzanas.","en":"Yes, please. I'll take two cheeses and four apples."},{"foreign":"El carrito está allí si necesita más. El horario está en la puerta.","en":"The shopping cart is over there if you need more. Opening hours are on the door."},{"foreign":"Gracias. ¿Puedo pagar con tarjeta de débito en caja, o con crédito?","en":"Thanks. Can I pay with a debit card at the checkout, or a credit card?"},{"foreign":"Las dos. Casi no usamos efectivo. Aquí tiene el cambio si lo necesita.","en":"Either. We're almost cashless. Here's change if you need it."},{"foreign":"Genial. También busco un regalo. Este jersey me queda grande. ¿Tienen otra talla?","en":"Great. I'm also looking for a gift. This sweater is too big. Do you have another size?"},{"foreign":"El probador está allí. Puede cambiarlo después o pedir un reembolso.","en":"The fitting room is there. You can exchange it later, or ask for a refund."},{"foreign":"El azul está bien. ¡Hasta luego!","en":"Blue is nice. Bye!"}],"glosses":{"oferta":"deal","supermercado":"supermarket","verduras":"vegetables","baratas":"cheap","pollo":"chicken","unidad":"each","bolsa":"bag","carrito":"shopping cart","horario":"opening hours","pagar":"to pay","débito":"debit","caja":"checkout","efectivo":"cash","cambio":"change","regalo":"gift","jersey":"sweater","grande":"too big","talla":"size","probador":"fitting room","cambiarlo":"to exchange","reembolso":"refund"}},{"id":"es-amigos","title":"Nuevos amigos","subtitle":"New friends","trail":"blue-square","categoryId":"es","sentences":[{"foreign":"Hola, me llamo Sam.","en":"Hi, my name is Sam."},{"foreign":"Encantado de verte. Soy Noor.","en":"Nice to see you. I'm Noor."},{"foreign":"¿De dónde eres?","en":"Where are you from?"},{"foreign":"De Canadá, pero ahora vivo aquí. ¿Y tú?","en":"From Canada, but I live here now. And you?"},{"foreign":"De aquí. ¿Qué estudias?","en":"From here. What do you study?"},{"foreign":"Informática. ¿Tienes planes este fin de semana?","en":"Computer science. Do you have plans this weekend?"},{"foreign":"Sí, una fiesta pequeña en casa de un amigo. ¿Estás libre? Estás invitado si quieres.","en":"Yes, a small party at a buddy's place. Are you free? You're invited if you want."},{"foreign":"¡Claro! Me gusta quedar con gente nueva. Mi afición es la fotografía.","en":"I'd love to! I like hanging out with new people. My hobby is photography."},{"foreign":"Genial. Es su cumpleaños, así que decimos feliz cumpleaños, ¡y salud!","en":"Really nice. It's his birthday, so we say happy birthday, and cheers!"},{"foreign":"¿Café después del seminario mañana? ¿O museo el fin de semana?","en":"Coffee after the seminar tomorrow? Or the museum this weekend?"},{"foreign":"Sí. Nos vemos pronto. Cuídate, y mantengamos el contacto.","en":"Yes. See you soon. Take care, and stay in touch!"}],"glosses":{"Encantado de verte":"nice to see you","De aquí":"from here","planes":"plans","fin de semana":"weekend","fiesta":"party","amigo":"friend","libre":"free","invitado":"invited","quedar":"hang out","afición":"hobby","fotografía":"photography","cumpleaños":"birthday","salud":"cheers","seminario":"seminar","Nos vemos pronto":"see you soon","Cuídate":"take care","contacto":"contact"}},{"id":"es-trabajo","title":"Primer día de trabajo","subtitle":"First day at work","trail":"black-diamond","categoryId":"es","sentences":[{"foreign":"Bienvenido al equipo, Sam. Esta es la oficina.","en":"Welcome to the team, Sam. This is the office."},{"foreign":"Gracias. Estoy un poco nervioso. ¿Es a tiempo completo o parcial?","en":"Thanks. I'm a bit nervous. Is it full-time or part-time?"},{"foreign":"A tiempo completo. Después de la contratación, el jefe presenta el proyecto.","en":"Full-time. After the hire, the boss presents the project."},{"foreign":"¿Dónde puedo dejar mis cosas?","en":"Where can I put my things?"},{"foreign":"Aquí junto a la ventana está tu mesa. La contraseña te la da un compañero.","en":"Here by the window is your desk. You'll get the password from a coworker."},{"foreign":"Si tienes preguntas, pregunta. La agenda está en la sala de reuniones.","en":"If you have questions, just ask. The agenda is in the meeting room."},{"foreign":"Entendido. ¿Quién es mi supervisor hoy?","en":"Understood. Who is my supervisor today?"},{"foreign":"Soy yo. La fecha límite de la primera factura al cliente es el viernes.","en":"That's me. The deadline for the first invoice to the client is Friday."},{"foreign":"Vale. ¿Cuándo llega el sueldo, y puedo teletrabajar algunos días?","en":"Ok. When does the salary come, and can I work from home some days?"},{"foreign":"Nómina el día 15. Mira la nómina. Teletrabajo después del periodo de prueba.","en":"Salary on the 15th. See the payslip. Remote work after the trial period."},{"foreign":"Genial. ¿Habrá viaje de negocios más adelante en el año?","en":"Great. Will there be a business trip later in the year?"},{"foreign":"Es posible. ¡Suerte!","en":"Possibly. Good luck!"}],"glosses":{"equipo":"team","oficina":"office","nervioso":"nervous","tiempo completo":"full-time","parcial":"part-time","contratación":"hire","jefe":"boss","proyecto":"project","mesa":"desk","contraseña":"password","compañero":"coworker","agenda":"agenda","sala de reuniones":"meeting room","supervisor":"supervisor","fecha límite":"deadline","factura":"invoice","cliente":"client","sueldo":"salary","nómina":"payslip","teletrabajar":"work remotely","periodo de prueba":"trial period","viaje de negocios":"business trip"}},{"id":"es-medico","title":"En el médico","subtitle":"At the doctor's","trail":"black-diamond","categoryId":"es","sentences":[{"foreign":"Buenos días. ¿Tiene cita ahora?","en":"Good day. Do you have an appointment now?"},{"foreign":"Sí. ¿Qué le pasa?","en":"Yes. What's the matter?"},{"foreign":"Llevo dos días con dolor de garganta y de cabeza. También me duele el oído.","en":"I've had a sore throat for two days, and a headache. Ear pain too."},{"foreign":"¿Tiene fiebre, tos u otros síntomas?","en":"Do you have a fever, a cough, or other symptoms?"},{"foreign":"Un poco de fiebre esta mañana, y un poco de tos. Sin dolor de estómago.","en":"A little fever this morning, and a bit of a cough. No stomachache."},{"foreign":"La enfermera le toma la tensión primero. Diga aaa.","en":"The nurse will take blood pressure first. Say ah."},{"foreign":"Parece un resfriado leve. ¿Es alérgico a algo?","en":"It looks like a mild cold. Are you allergic to anything?"},{"foreign":"No. ¿Necesito receta para la medicina?","en":"No. Do I need a prescription for medicine?"},{"foreign":"Todavía no. Reposo, agua y paracetamol. Vuelva si empeora.","en":"Not yet. Rest, water, and paracetamol. Come back if it gets worse."},{"foreign":"Muchas gracias. ¿Puedo pedir la baja si empeora?","en":"Thank you. Can I get a sick note if it gets worse?"},{"foreign":"Sí. En una emergencia: llame al 112, o vaya a urgencias.","en":"Yes. In an emergency: call 112, or go to A&E / the ER."}],"glosses":{"cita":"appointment","dolor de garganta":"sore throat","dolor de cabeza":"headache","oído":"ear","fiebre":"fever","tos":"cough","síntomas":"symptoms","estómago":"stomach","enfermera":"nurse","tensión":"blood pressure","resfriado":"cold","alérgico":"allergic","receta":"prescription","medicina":"medicine","paracetamol":"paracetamol","baja":"sick note","emergencia":"emergency","urgencias":"ER"}},{"id":"es-piso","title":"Buscando una habitación","subtitle":"Looking for a room","trail":"black-diamond","categoryId":"es","sentences":[{"foreign":"Hola, llamo por el piso de internet.","en":"Hi, I'm calling about the apartment online."},{"foreign":"Sí, sigue libre. ¿Cuándo quiere verlo?","en":"Yes, it's still free. When would you like to see it?"},{"foreign":"Esta tarde me va bien, hacia las tres.","en":"This afternoon works, around three."},{"foreign":"Bien. Está en el barrio, tercer piso. Es un piso compartido. Usted será inquilino.","en":"Fine. It's in the neighborhood, third floor. It's a shared flat. You'll be a tenant."},{"foreign":"¿Hay ascensor? Solo tengo una maleta con ropa. El hotel sale caro a largo plazo.","en":"Is there an elevator? I only have a suitcase with clothes. A hotel is too expensive long-term."},{"foreign":"No, solo escaleras. El dormitorio es luminoso, y hay balcón.","en":"No, only stairs. The bedroom is bright, and there is a balcony."},{"foreign":"¿Y el salón y el lavadero? ¿Alguna gotera en el baño?","en":"What about the living room and the laundry room? Any leak in the bathroom?"},{"foreign":"Compartido. Sin goteras. El alquiler incluye internet; los gastos comunes van aparte.","en":"Shared. No leak. The rent includes internet; shared costs come extra."},{"foreign":"¿Y hay fianza? ¿Cuándo recibo las llaves?","en":"And is there a deposit? When do I get keys?"},{"foreign":"Sí, un mes. El casero le espera en el buzón con el contrato.","en":"Yes, one month. The landlord will meet you at the mailbox with the lease."},{"foreign":"Perfecto. Avíseme si el vecino se queja del ruido. Yo soy callado.","en":"Great. Let me know if the neighbor complains about noise. I'm quiet."}],"glosses":{"piso":"apartment","libre":"available","barrio":"neighborhood","compartido":"shared","inquilino":"tenant","ascensor":"elevator","maleta":"suitcase","hotel":"hotel","dormitorio":"bedroom","balcón":"balcony","salón":"living room","lavadero":"laundry room","gotera":"leak","alquiler":"rent","gastos comunes":"shared costs","fianza":"deposit","llaves":"keys","casero":"landlord","buzón":"mailbox","contrato":"lease","vecino":"neighbor","ruido":"noise"}},{"id":"es-huelga","title":"Huelga en el metro","subtitle":"Subway strike","trail":"double-black-diamond","categoryId":"es","sentences":[{"foreign":"¿Viste la noticia esta mañana?","en":"Did you see the news this morning?"},{"foreign":"No, ¿qué ha pasado?","en":"No, what happened?"},{"foreign":"Mañana hay huelga en el metro y en varias líneas.","en":"Tomorrow there's a strike on the subway and on several lines."},{"foreign":"¿Entonces no van los trenes en hora punta?","en":"So the trains won't run in rush hour?"},{"foreign":"Muchos paran. Habrá bus de enlace desde la cabecera.","en":"Many will stop. There will be a replacement bus from the terminus."},{"foreign":"Cojo la bici pública, aunque llueva en la acera.","en":"I'll take the city bike, even if it rains on the sidewalk."},{"foreign":"Listo. ¿O teletrabajas mañana?","en":"Smart. Or are you working from home tomorrow?"},{"foreign":"Quizá. Hablo primero con el jefe y miro el presupuesto para un taxi.","en":"Maybe. I'll talk to the manager first, and check the budget for a taxi."},{"foreign":"La rotonda de la estación será un caos. Coge el tranvía si va.","en":"The roundabout by the station will be chaos. Take the tram if it runs."},{"foreign":"Vale. Avísame si se cancela la salida.","en":"Alright. Keep me posted if the departure is cancelled."}],"glosses":{"noticia":"news","huelga":"strike","metro":"subway","líneas":"lines","hora punta":"rush hour","bus de enlace":"replacement bus","cabecera":"terminus","bici pública":"city bike","acera":"sidewalk","teletrabajas":"work remotely","jefe":"manager","presupuesto":"budget","taxi":"taxi","rotonda":"roundabout","tranvía":"tram","salida":"departure","cancela":"is cancelled"}},{"id":"es-debate","title":"Un debate corto","subtitle":"A short debate","trail":"double-black-diamond","categoryId":"es","sentences":[{"foreign":"Creo que el transporte público es muy importante.","en":"I think public transport is really important."},{"foreign":"¿Por qué?","en":"Why?"},{"foreign":"Porque no todo el mundo puede tener coche en hora punta, y las tarifas de aparcamiento son altas.","en":"Because not everyone can have a car in rush hour, and parking fees are high."},{"foreign":"Pero los autobuses van siempre llenos y con retraso. El precio del billete también sube.","en":"But the buses are always full and late. The ticket price is rising too."},{"foreign":"Si invertimos más en líneas, mejora. Mira el presupuesto de la ciudad.","en":"If we invest more in lines, it gets better. Look at the city budget."},{"foreign":"A largo plazo, quizá. Ahora es caro. Los intereses y los préstamos aprietan a la gente.","en":"In the long run, maybe. Right now it's expensive. Interest and loans put pressure on people."},{"foreign":"Cierto. Aun así, creo que merece la pena. Se puede destinar más al transporte público.","en":"True. Even so, I think it's worth it. You can put more into public transport."},{"foreign":"Leamos más antes de decidir. Miro mi cuenta después de comer.","en":"Let's read more before we decide. I'll check my account after lunch."},{"foreign":"Vale. Nos vemos en el cajero de la estación y seguimos hablando.","en":"Alright. We'll meet at the ATM at the station and talk more."}],"glosses":{"transporte público":"public transport","hora punta":"rush hour","tarifas":"fees","aparcamiento":"parking","retraso":"delay","billete":"ticket","líneas":"lines","presupuesto":"budget","intereses":"interest","préstamos":"loans","merece la pena":"worth it","cuenta":"account","comer":"lunch","cajero":"ATM"}},{"id":"es-planes","title":"Planes para el verano","subtitle":"Summer plans","trail":"double-black-diamond","categoryId":"es","sentences":[{"foreign":"¿Qué vas a hacer en verano?","en":"What are you going to do this summer?"},{"foreign":"Quiero viajar unas semanas, si se puede. ¿Tienes planes?","en":"I want to travel a few weeks, if it works out. Do you have plans?"},{"foreign":"Quizá a Andalucía. Esta noche reservo ida y vuelta en la app.","en":"Maybe to Andalusia. I'm booking a round-trip in the app tonight."},{"foreign":"¿Tienes el pasaporte listo? El equipaje pasa por el facturado y el control de pasaportes.","en":"Is your passport ready? The luggage has to go through check-in and passport control."},{"foreign":"Sí. Solo equipaje de mano. La puerta y el asiento salen en la tarjeta de embarque después de seguridad.","en":"Yes. Hand luggage only. Gate and seat are on the boarding pass after security."},{"foreign":"El embarque empieza pronto. Después del aterrizaje recoges la maleta en la cinta.","en":"Boarding starts early. After landing you pick up the suitcase on the baggage carousel."},{"foreign":"Yo me quedo y hago horas extra. El ahorro va a mi presupuesto y a las cuotas del préstamo.","en":"I'm staying and working overtime. The savings go into my budget and loan installments."},{"foreign":"Práctico. Mi vuelo puede retrasarse. La llegada es tarde de todos modos.","en":"Practical. My flight might be delayed. Arrival is late either way."},{"foreign":"Avísame cuando aterrices. La terminal es fácil de encontrar.","en":"Let me know when you land. The terminal is easy to find."},{"foreign":"Claro. Mantente al tanto. ¡Buen viaje!","en":"Will do. Keep me posted. Have a good departure!"}],"glosses":{"planes":"plans","reservo":"am booking","ida y vuelta":"round-trip","pasaporte":"passport","equipaje":"luggage","facturado":"checked baggage / check-in","control de pasaportes":"passport control","equipaje de mano":"hand luggage","puerta":"gate","asiento":"seat","tarjeta de embarque":"boarding pass","seguridad":"security","embarque":"boarding","cinta":"baggage carousel","horas extra":"overtime","presupuesto":"budget","cuotas":"installments","préstamo":"loan","retrasarse":"be delayed","llegada":"arrival","aterrices":"land","terminal":"terminal"}}]);
